insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('58316', 'o.rang', 'orang', '', '', '["Nomina","Nomina","Nomina","Nomina","Nomina","Nomina","Nomina","Nomina","Nomina","Nomina","Cakapan"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"manusia (dalam arti khusus)","contoh":[]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"manusia (ganti diri ketiga yang tidak tentu)","contoh":[{"nomor":2,"teks":"jangan lekas percaya pada mulut --"}]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"dirinya sendiri; manusianya sendiri","contoh":[{"nomor":2,"teks":"saya tidak bertemu dengan --nya"}]},{"nomor":"4","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"kata penggolong untuk manusia","contoh":[{"nomor":2,"teks":"lima -- nelayan"}]},{"nomor":"5","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"anak buah (bawahan)","contoh":[{"nomor":2,"teks":"mereka itu --nya Pak Camat"}]},{"nomor":"6","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"rakyat (dari suatu negara); warga negara","contoh":[{"nomor":2,"teks":"-- Pakistan"}]},{"nomor":"7","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"manusia yang berasal dari atau tinggal di suatu daerah (desa, kota, negara, dan sebagainya)","contoh":[{"nomor":2,"teks":"dia -- Bogor"},{"nomor":4,"teks":"suaminya -- Eropa"}]},{"nomor":"8","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"suku bangsa","contoh":[]},{"nomor":"9","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"manusia lain; bukan diri sendiri; bukan kaum (golongan, kerabat) sendiri: negeri lain (bukan negeri kita)","contoh":[{"nomor":2,"teks":"jangankan anak sendiri, anak -- pun saya tolong"},{"nomor":4,"teks":"negeri --"}]},{"nomor":"10","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"cak","nama":"Cakapan","tipe":"kelas_kata"}],"definisi":"karena (sebenarnya)","contoh":[{"nomor":2,"teks":"mana dapat membayar, -- belum gajian"},{"nomor":4,"teks":"-- berdendang di pentasnya"}]}]', null, '["berorang-orang","keseorangan","mengorangkan","orang-orangan","perorangan","perseorangan","seorang","seseorang"]', '["orang aluan","orang am","orang ampek jinih","orang antum","orang asing","orang atasan","orang awak","orang awam","orang awas","orang banyak","orang Barat","orang basaga","orang bati","orang batu","orang belakang","orang berdasi","orang besar","orang biasa","orang buangan","orang burok","orang dagang","orang dalam","orang dengar","orang gajian","orang gedean","orang gila","orang halimunan","orang halus","orang hanyut","orang helat","orang hilir","orang hulu","orang hutan","orang jauh","orang kampung","orang kasim","orang kaum","orang kaya","orang keblangsak","orang ketiga","orang kota","orang kudus","orang kulit putih","orang lalu","orang luar","orang luntang-lantung","orang lurus","orang merdeka","orang muda","orang ombak","orang palung","orang pangan","orang patut","orang pesisir","orang pintar","orang ramai","orang rimba","orang rumah","orang sabun","orang sebelah","orang semenda","orang setangga","orang sipil","orang suci","orang tanah","orang tani","orang tengah","orang tepi","orang terlantar","orang Timur","orang toksik","orang tua","orang tua angkat","orang tua asuh","orang tua baptis","orang tua biologis","orang tua helikopter","orang tua tunggal","orang Tugu","orang udik"]', '["air orang disauk, ranting orang dipatah, adat orang diturut","akar yang membesarkan, buah yang disanjung orang","anak orang, anak orang juga","asing orang, lain pendapat","awak yang payah membelah ruyung, orang lain yang beroleh sagunya","bagai bertemu alu dengan lesung, beras kita yang terserak, ayam orang yang kenyang","bagai orang bujang baru berkeris","bagai orang kena miang","bagai rupa orang terkena beragih","bak menanti orang dahulu, bak melalah orang kudian","banyak orang, banyak ragamnya","berkelahi dengan orang tak berambut","berlidah di lidah orang","bermalam di bawah nyiur pinang orang, kata orang diturut","bermulut di mulut orang","bersawah seperempat piring, ke sawah sama dengan orang","biar miskin asal cerdik, terlawan jua orang kaya","dengar cakap enggang, makan buah beluluk, dengar cakap orang, terjun masuk lubuk","di padang orang berlari, di padang sendiri berjingkat","diserakkan padi awak diimbaukan orang lain","dari jauh orang angkat telunjuk, kalau dekat dia angkat mata","harimau mati meninggalkan belang, gajah mati meninggalkan gading, orang mati meninggalkan nama","hidup di ujung gurung orang","hujan emas di negeri orang, hujan batu di negeri sendiri, baik jua di negeri sendiri","hujan keris lembing di negeri kita, hujan emas perak di negeri orang, baik jua di negeri kita","ilmu dan akal dihalai-balai, itulah tanda orang yang lalai","isi lemak dapat ke orang, tulang bulu pulang ke kita","jalan dialih orang lalu, cupak dipapak orang penggalas","kalau laba bercikun-cikun, buruk diberi tahu orang","kena kecipak orang berbelut","kerbau jangan dimaling orang, ayam jangan dimusangi","kucing melompat, orang terkejut dari tidurnya, ayam berkokok, hari pun siang","kurang-kurang dikerah orang, lebih-lebih dia hendak datang","lain dulang lain kaki, lain orang lain hati","lain orang memperanakkan, lain orang dipanggil bapa","membawakan cupak ke negeri orang","memberi lauk kepada orang membantai","menari (merentak) di ladang orang","mengairi sawah orang","mengajar orang tua makan dadih","mengata dulang paku serpih, mengata orang awak yang lebih","mengunyah orang bergigi","menunjukkan ilmu kepada orang menetak","menyandang lemang hangat orang","menyinggung mata bisul orang","minta dedak kepada orang mengubik","minum darah orang","misai bertaring bagai panglima, sebulan sekali tak membunuh orang","mulut kapuk dapat ditutup, mulut orang tidak","orang beraja di hatinya","orang berdendang di pentasnya","orang bergayung sama pandai, bak kundi atas dulang","orang dahaga diberi air","orang gelincir air","orang haus diberi air, orang lapar diberi nasi","orang kaya jangan diangan-angan, orang miskin jangan dihina","orang kaya tempat meminta, orang pintar tempat bertanya","orang mandi bersiselam, awak mandi bertimba","orang mengantuk disorongkan bantal","orang muda selendang dunia, orang kaya suka dimakan","orang pembuat periuk, bertanak di tembikar","orang penggamang mati jatuh","orang terpegang pada hulunya, awak terpegang pada matanya","orang timpang jangan dicacat, ingat-ingat hari belakang","orang tua diajar makan pisang","orang yang selancaran alu, atap yang berjahit, bendul bertekan","padi selumbung dimakan orang banyak","pejatian awak, kepantangan orang","pencarak benak orang","pergi tempat bertanya, pulang tempat berberita (berkenaan dengan orang cerdik pandai)","sebagai orang mabuk gadung","semalam di bawah nyiur pinang orang, kata diturut","seperti menanti orang dahulu, mengejar orang kemudian","seperti orang kecabaian","seperti orang mati, jika tiada orang mengangkat, bila akan bergerak","sukar kaji pada orang alim, sukar uang pada orang kaya","tak ada guruh bagi orang pekak, tak ada kilat bagi orang buta","tidak ada orang menggaruk ke luar badan","tidak dibawa orang sehilir semudik"]', '["berat pada mata orang lain","bergelanggang di mata orang banyak","di bawah ketiak orang","makan keringat orang","menari di atas genderang orang lain","mengerami telur orang","menodai nama orang tua","orang darat bongkong","termakan perbuatan orang"]', '[{"peribahasa":"air orang disauk, ranting orang dipatah, adat orang diturut","makna":"Di mana bumi dipijak, di situ langit dijunjung; kita harus mengikuti adat istiadat tempat kita tinggal."},{"peribahasa":"akar yang membesarkan, buah yang disanjung orang","makna":"Orang yang bekerja keras sering kali tidak mendapat penghargaan, sementara pemimpin atau atasannya yang dipuji."},{"peribahasa":"anak orang, anak orang juga","makna":"Meskipun kita menyayangi anak orang lain seperti anak sendiri, ikatan darah tetap berbeda."},{"peribahasa":"asing orang, lain pendapat","makna":"Setiap orang memiliki pandangan atau pendapat yang berbeda-beda."},{"peribahasa":"awak yang payah membelah ruyung, orang lain yang beroleh sagunya","makna":"Orang lain yang bekerja keras, tetapi orang lain yang mendapatkan hasilnya."},{"peribahasa":"bagai bertemu alu dengan lesung, beras kita yang terserak, ayam orang yang kenyang","makna":"Pertengkaran antara sesama kawan atau keluarga hanya akan menguntungkan pihak luar."},{"peribahasa":"bagai orang bujang baru berkeris","makna":"Seseorang yang sombong karena baru memiliki sesuatu yang berharga."},{"peribahasa":"bagai orang kena miang","makna":"Sangat gelisah atau tidak tenang."},{"peribahasa":"bagai rupa orang terkena beragih","makna":"Seseorang yang tampak sangat pucat dan kebingungan."},{"peribahasa":"bak menanti orang dahulu, bak melalah orang kudian","makna":"Seseorang yang selalu menjadi panutan atau teladan bagi orang lain."},{"peribahasa":"banyak orang, banyak ragamnya","makna":"Setiap orang memiliki sifat, watak, dan keinginan yang berbeda-beda."},{"peribahasa":"berkelahi dengan orang tak berambut","makna":"Mencari masalah dengan orang yang tidak sepadan atau tidak akan memberi keuntungan apa pun."},{"peribahasa":"berlidah di lidah orang","makna":"Hanya meniru atau mengikuti perkataan orang lain tanpa memiliki pendirian sendiri."},{"peribahasa":"bermalam di bawah nyiur pinang orang, kata orang diturut","makna":"Jika kita menumpang atau bergantung pada orang lain, kita harus mengikuti aturan atau kehendak mereka."},{"peribahasa":"bermulut di mulut orang","makna":"Hanya meniru atau mengikuti perkataan orang lain tanpa memiliki pendirian sendiri."},{"peribahasa":"bersawah seperempat piring, ke sawah sama dengan orang","makna":"Meskipun memiliki sedikit harta, tetapi gaya hidupnya meniru orang kaya."},{"peribahasa":"biar miskin asal cerdik, terlawan jua orang kaya","makna":"Kecerdikan dan akal lebih berharga daripada kekayaan."},{"peribahasa":"dengar cakap enggang, makan buah beluluk, dengar cakap orang, terjun masuk lubuk","makna":"Mengikuti nasihat yang salah atau menyesatkan akan membawa celaka."},{"peribahasa":"di padang orang berlari, di padang sendiri berjingkat","makna":"Di tempat orang lain berani berbuat macam-macam, tetapi di tempat sendiri takut."},{"peribahasa":"diserakkan padi awak diimbaukan orang lain","makna":"Mengharapkan bantuan dari orang lain, padahal diri sendiri memiliki kemampuan."},{"peribahasa":"dari jauh orang angkat telunjuk, kalau dekat dia angkat mata","makna":"Seseorang yang dihormati dari jauh, tetapi jika sudah dekat akan diremehkan."},{"peribahasa":"harimau mati meninggalkan belang, gajah mati meninggalkan gading, orang mati meninggalkan nama","makna":"Setiap orang akan dikenang karena perbuatan baik atau buruknya setelah ia meninggal dunia."},{"peribahasa":"hidup di ujung gurung orang","makna":"Hidup bergantung sepenuhnya pada belas kasihan orang lain."},{"peribahasa":"hujan emas di negeri orang, hujan batu di negeri sendiri, baik jua di negeri sendiri","makna":"Meskipun negeri orang lain tampak lebih makmur dan menyenangkan, negeri sendiri tetap lebih baik."},{"peribahasa":"hujan keris lembing di negeri kita, hujan emas perak di negeri orang, baik jua di negeri kita","makna":"Meskipun negeri sendiri penuh dengan kesulitan dan bahaya, sedangkan negeri orang lain tampak makmur, negeri sendiri tetap lebih baik."},{"peribahasa":"ilmu dan akal dihalai-balai, itulah tanda orang yang lalai","makna":"Orang yang tidak menggunakan ilmu dan akalnya adalah orang yang merugi."},{"peribahasa":"isi lemak dapat ke orang, tulang bulu pulang ke kita","makna":"Orang lain yang mendapatkan keuntungan, sementara kita hanya menanggung kerugian atau kesusahan."},{"peribahasa":"jalan dialih orang lalu, cupak dipapak orang penggalas","makna":"Adat atau kebiasaan yang sudah umum tidak dapat diubah lagi."},{"peribahasa":"kalau laba bercikun-cikun, buruk diberi tahu orang","makna":"Jika mendapat keuntungan sedikit, jangan cepat-cepat diberitahukan kepada orang lain."},{"peribahasa":"kena kecipak orang berbelut","makna":"Ikut terseret dalam masalah orang lain."},{"peribahasa":"kerbau jangan dimaling orang, ayam jangan dimusangi","makna":"Harta benda harus dijaga dengan baik agar tidak hilang atau dicuri."},{"peribahasa":"kucing melompat, orang terkejut dari tidurnya, ayam berkokok, hari pun siang","makna":"Setiap peristiwa memiliki tanda-tanda atau sebabnya masing-masing."},{"peribahasa":"kurang-kurang dikerah orang, lebih-lebih dia hendak datang","makna":"Orang yang malas atau tidak mau berusaha, tetapi jika ada keuntungan akan segera datang."},{"peribahasa":"lain dulang lain kaki, lain orang lain hati","makna":"Setiap orang memiliki keinginan dan pendapat yang berbeda-beda."},{"peribahasa":"lain orang memperanakkan, lain orang dipanggil bapa","makna":"Orang lain yang melahirkan, tetapi orang lain yang memelihara dan dianggap sebagai orang tua."},{"peribahasa":"membawakan cupak ke negeri orang","makna":"Mengajarkan adat atau kebiasaan sendiri kepada orang lain yang sudah memiliki adatnya sendiri."},{"peribahasa":"memberi lauk kepada orang membantai","makna":"Memberi bantuan kepada orang yang sudah kaya atau tidak membutuhkan."},{"peribahasa":"menari (merentak) di ladang orang","makna":"Bersenang-senang di atas penderitaan atau milik orang lain."},{"peribahasa":"mengairi sawah orang","makna":"Memberi keuntungan kepada orang lain."},{"peribahasa":"mengajar orang tua makan dadih","makna":"Mengajari orang yang lebih berpengalaman atau pandai."},{"peribahasa":"mengata dulang paku serpih, mengata orang awak yang lebih","makna":"Mencela orang lain, padahal diri sendiri lebih buruk."},{"peribahasa":"mengunyah orang bergigi","makna":"Melakukan sesuatu yang sesuai dengan kemampuan atau keahliannya."},{"peribahasa":"menunjukkan ilmu kepada orang menetak","makna":"Mengajari orang yang lebih ahli."},{"peribahasa":"menyandang lemang hangat orang","makna":"Menanggung akibat dari perbuatan orang lain."},{"peribahasa":"menyinggung mata bisul orang","makna":"Mencari masalah atau membuat orang lain marah."},{"peribahasa":"minta dedak kepada orang mengubik","makna":"Meminta bantuan kepada orang yang tidak memiliki apa-apa."},{"peribahasa":"minum darah orang","makna":"Menindas atau memeras orang lain."},{"peribahasa":"misai bertaring bagai panglima, sebulan sekali tak membunuh orang","makna":"Orang yang penampilannya gagah berani, tetapi sebenarnya penakut."},{"peribahasa":"mulut kapuk dapat ditutup, mulut orang tidak","makna":"Sangat sulit untuk menghentikan omongan atau gosip orang lain."},{"peribahasa":"orang beraja di hatinya","makna":"Setiap orang memiliki kebebasan untuk berbuat sesuai keinginannya."},{"peribahasa":"orang berdendang di pentasnya","makna":"Setiap orang memiliki tempat dan perannya masing-masing."},{"peribahasa":"orang bergayung sama pandai, bak kundi atas dulang","makna":"Dua orang yang sama-sama ahli atau pandai dalam bidangnya."},{"peribahasa":"orang dahaga diberi air","makna":"Memberikan pertolongan kepada orang yang sangat membutuhkannya."},{"peribahasa":"orang gelincir air","makna":"Orang yang sangat licik atau pandai menipu."},{"peribahasa":"orang haus diberi air, orang lapar diberi nasi","makna":"Memberikan pertolongan kepada orang yang sangat membutuhkannya."},{"peribahasa":"orang kaya jangan diangan-angan, orang miskin jangan dihina","makna":"Jangan hanya berkhayal menjadi kaya, dan jangan merendahkan orang miskin."},{"peribahasa":"orang kaya tempat meminta, orang pintar tempat bertanya","makna":"Setiap orang memiliki kelebihan dan perannya masing-masing dalam masyarakat."},{"peribahasa":"orang mandi bersiselam, awak mandi bertimba","makna":"Orang lain mendapatkan keuntungan besar dengan mudah, sementara kita harus bersusah payah untuk mendapatkan hasil yang sedikit."},{"peribahasa":"orang mengantuk disorongkan bantal","makna":"Mendapatkan sesuatu yang sangat diinginkan atau dibutuhkan."},{"peribahasa":"orang muda selendang dunia, orang kaya suka dimakan","makna":"Orang muda sering kali lalai dan suka bersenang-senang, sementara orang kaya sering kali menjadi sasaran penipuan."},{"peribahasa":"orang pembuat periuk, bertanak di tembikar","makna":"Orang yang memiliki keahlian atau sumber daya, tetapi hidup dalam kekurangan."},{"peribahasa":"orang penggamang mati jatuh","makna":"Orang yang penakut akan celaka karena ketakutannya sendiri."},{"peribahasa":"orang terpegang pada hulunya, awak terpegang pada matanya","makna":"Dalam suatu perselisihan, satu pihak memiliki keuntungan lebih besar daripada pihak lain."},{"peribahasa":"orang timpang jangan dicacat, ingat-ingat hari belakang","makna":"Jangan mencela kekurangan orang lain, karena kita tidak tahu apa yang akan terjadi pada diri kita di masa depan."},{"peribahasa":"orang tua diajar makan pisang","makna":"Mengajari orang yang lebih berpengalaman atau pandai."},{"peribahasa":"orang yang selancaran alu, atap yang berjahit, bendul bertekan","makna":"Orang yang memiliki kekuasaan atau pengaruh besar."},{"peribahasa":"padi selumbung dimakan orang banyak","makna":"Kekayaan yang melimpah akan habis juga jika digunakan oleh banyak orang."},{"peribahasa":"pejatian awak, kepantangan orang","makna":"Sesuatu yang baik bagi kita, belum tentu baik bagi orang lain."},{"peribahasa":"pencarak benak orang","makna":"Orang yang suka membuat orang lain bingung atau pusing."},{"peribahasa":"pergi tempat bertanya, pulang tempat berberita (berkenaan dengan orang cerdik pandai)","makna":"Orang yang cerdik pandai selalu menjadi tempat untuk bertanya dan mendapatkan informasi."},{"peribahasa":"sebagai orang mabuk gadung","makna":"Seseorang yang berjalan terhuyung-huyung karena mabuk."},{"peribahasa":"semalam di bawah nyiur pinang orang, kata diturut","makna":"Jika kita menumpang atau bergantung pada orang lain, kita harus mengikuti aturan atau kehendak mereka."},{"peribahasa":"seperti menanti orang dahulu, mengejar orang kemudian","makna":"Seseorang yang selalu menjadi panutan atau teladan bagi orang lain."},{"peribahasa":"seperti orang kecabaian","makna":"Sangat gelisah atau tidak tenang karena marah."},{"peribahasa":"seperti orang mati, jika tiada orang mengangkat, bila akan bergerak","makna":"Orang yang sangat malas dan tidak mau berusaha tanpa bantuan orang lain."},{"peribahasa":"sukar kaji pada orang alim, sukar uang pada orang kaya","makna":"Tidak mungkin orang alim kekurangan ilmu, dan tidak mungkin orang kaya kekurangan uang."},{"peribahasa":"tak ada guruh bagi orang pekak, tak ada kilat bagi orang buta","makna":"Nasihat atau peringatan tidak akan berguna bagi orang yang tidak mau mendengarkan."},{"peribahasa":"tidak ada orang menggaruk ke luar badan","makna":"Setiap orang pasti akan membela kepentingannya sendiri atau keluarganya."},{"peribahasa":"tidak dibawa orang sehilir semudik","makna":"Seseorang yang tidak dianggap penting atau tidak diajak berunding."}]');
